<?php
require_once __DIR__.'/../includes/header.php';require_once __DIR__.'/../config/database.php';check_access([3]);$db=Database::getInstance();
$stmt=$db->prepare('SELECT id,kelas_id FROM siswa WHERE user_id=?');$stmt->execute([$_SESSION['user_id']]);$siswa=$stmt->fetch();$sid=(int)($siswa['id']??0);$kelas=(int)($siswa['kelas_id']??0);
$filter=$_GET['status']??'tersedia';if(!in_array($filter,['tersedia','selesai','semua'],true))$filter='tersedia';
$where=$filter==='tersedia'?" AND u.waktu_selesai>=NOW() AND (su.id IS NULL OR su.status<>'Selesai')":($filter==='selesai'?" AND su.status='Selesai'":'');
$stmt=$db->prepare("SELECT u.id,u.nama_ujian,u.jenis_ujian,u.durasi_menit,u.waktu_mulai,u.waktu_selesai,m.nama_mapel,g.nama_lengkap nama_guru,su.status status_sesi,nu.nilai_total FROM ujian u JOIN pengajaran p ON p.id=u.pengajaran_id JOIN mapel m ON m.id=p.mapel_id JOIN guru g ON g.id=p.guru_id LEFT JOIN sesi_ujian su ON su.ujian_id=u.id AND su.siswa_id=? LEFT JOIN nilai_ujian nu ON nu.ujian_id=u.id AND nu.siswa_id=? WHERE p.kelas_id=? $where ORDER BY u.waktu_mulai DESC");
$stmt->execute([$sid,$sid,$kelas]);$list=$stmt->fetchAll();
?>
