<div id="page-content-wrapper" class="exam-list-page"><nav class="navbar top-navbar px-3 px-md-4 py-3"><div><h5 class="fw-bold mb-0"><i class="fa-solid fa-file-pen text-danger me-2"></i>Ujian Saya</h5><small class="text-muted">Jadwal kuis dan ujian kelas</small></div></nav><main class="exam-list-main p-3 p-md-4">
<div class="d-flex gap-2 overflow-auto pb-2 mb-2"><?php foreach(['tersedia'=>'Tersedia','selesai'=>'Selesai','semua'=>'Semua'] as $key=>$label): ?><a class="btn btn-sm <?= $filter===$key?'btn-primary':'btn-light' ?>" href="?status=<?= $key ?>"><?= $label ?></a><?php endforeach ?></div>
<div class="row g-3"><?php foreach($list as $u): $now=time();$mulai=strtotime($u['waktu_mulai']);$akhir=strtotime($u['waktu_selesai']);$done=$u['status_sesi']==='Selesai';$running=$now>=$mulai&&$now<=$akhir&&!$done; ?><div class="col-12 col-md-6"><article class="card exam-list-card h-100"><div class="card-body p-3 d-flex flex-column"><div class="d-flex justify-content-between gap-2 mb-2"><span class="badge bg-primary-subtle text-primary"><?= sanitize($u['nama_mapel']) ?></span><span class="badge <?= $done?'bg-success':($running?'bg-danger':'bg-secondary') ?>"><?= $done?'Selesai':($running?'Berlangsung':($now<$mulai?'Akan Datang':'Berakhir')) ?></span></div><h2 class="h6 fw-bold exam-title-copy"><?= sanitize($u['nama_ujian']) ?></h2><p class="small text-muted mb-2"><?= sanitize($u['jenis_ujian']) ?> · <?= (int)$u['durasi_menit'] ?> menit · <?= sanitize($u['nama_guru']) ?></p><div class="small border rounded p-2 mb-3 bg-light"><i class="fa-regular fa-calendar me-1"></i><?= date('d/m/Y H:i',$mulai) ?> s.d. <?= date('d/m/Y H:i',$akhir) ?></div><div class="mt-auto"><?php if($done): ?><div class="alert alert-success py-2 text-center mb-0">Sudah dikerjakan<?php if($u['nilai_total']!==null): ?> · Nilai <?= number_format($u['nilai_total'],2) ?><?php endif ?></div><?php elseif($running): ?><a class="btn btn-danger w-100" href="ujian_kerjakan.php?id=<?= (int)$u['id'] ?>"><i class="fa-solid fa-play me-1"></i><?= $u['status_sesi']==='Berlangsung'?'Lanjutkan':'Mulai' ?> Ujian</a><?php elseif($now<$mulai): ?><button class="btn btn-light w-100" disabled>Belum Dimulai</button><?php else: ?><button class="btn btn-secondary w-100" disabled>Jadwal Berakhir</button><?php endif ?></div></div></article></div><?php endforeach ?></div>
<?php if(!$list): ?><div class="card exam-list-card text-center p-5"><i class="fa-solid fa-calendar-check fa-2x text-success mb-2"></i><p class="text-muted mb-0">Tidak ada ujian pada kategori ini.</p></div><?php endif ?>
</main></div><?php require_once __DIR__.'/../includes/footer.php'; ?>
